162:     private void maybeRemoveFromInflightBatches(ProducerBatch batch) {
163:         List<ProducerBatch> batches = inFlightBatches.get(batch.topicPartition);
164:         if (batches != null) {
165:             batches.remove(batch);
166:             if (batches.isEmpty()) {
167:                 inFlightBatches.remove(batch.topicPartition);
168:             }
169:         }
170:     }
171: 
172:     private void maybeRemoveAndDeallocateBatch(ProducerBatch batch) {
173:         maybeRemoveFromInflightBatches(batch);
174:         this.accumulator.deallocate(batch);
175:     }
