301:     /**
302:      * Run a single iteration of sending
303:      *
304:      */
305:     void runOnce() {
306:         if (transactionManager != null) {
307:             try {
308:                 transactionManager.maybeResolveSequences();
309: 
310:                 RuntimeException lastError = transactionManager.lastError();
311: 
312:                 // do not continue sending if the transaction manager is in a failed state
313:                 if (transactionManager.hasFatalError()) {
314:                     if (lastError != null)
315:                         maybeAbortBatches(lastError);
316:                     client.poll(retryBackoffMs, time.milliseconds());
317:                     return;
318:                 }
319: 
320:                 if (transactionManager.hasAbortableError() && shouldHandleAuthorizationError(lastError)) {
321:                     return;
322:                 }
323: 
324:                 // Check whether we need a new producerId. If so, we will enqueue an InitProducerId
325:                 // request which will be sent below
326:                 transactionManager.bumpIdempotentEpochAndResetIdIfNeeded();
327: 
328:                 if (maybeSendAndPollTransactionalRequest()) {
329:                     return;
330:                 }
331:             } catch (AuthenticationException e) {
332:                 // This is already logged as error, but propagated here to perform any clean ups.
333:                 log.trace("Authentication exception while processing transactional request", e);
334:                 transactionManager.authenticationFailed(e);
335:             }
336:         }
337: 
338:         long currentTimeMs = time.milliseconds();
339:         long pollTimeout = sendProducerData(currentTimeMs);
340:         client.poll(pollTimeout, currentTimeMs);
341:     }
